/// Note: Uses `WaitForPending` to block until at least one payload build completes,
/// enabling eager payload fetching without fixed delays on the consensus side.
pub async fn resolve(&self, id: PayloadId) -> Option<Result<T::BuiltPayload, PayloadBuilderError>> {
    self.resolve_kind(id, PayloadKind::WaitForPending).await
}
